using UnityEngine;

public class MusicManager : MonoBehaviour
{
    public static MusicManager Instance;

    public AudioClip menuMusic;
    public AudioClip gameplayMusic;
    public AudioClip bossMusic;
    public AudioClip victoryMusic;

    private AudioSource musicSource;
    private AudioSource transitionSource;

    private float targetVolume = 1f;
    private float fadeSpeed = 0.5f;
    private bool isFading = false;

    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }

        // Create audio sources
        musicSource = gameObject.AddComponent<AudioSource>();
        transitionSource = gameObject.AddComponent<AudioSource>();

        musicSource.loop = true;
        musicSource.volume = 0.8f;
        transitionSource.loop = true;
        transitionSource.volume = 0f;
    }

    void Update()
    {
        // Handle crossfade
        if (isFading)
        {
            transitionSource.volume = Mathf.Lerp(transitionSource.volume, targetVolume, fadeSpeed * Time.deltaTime);
            musicSource.volume = Mathf.Lerp(musicSource.volume, 1f - targetVolume, fadeSpeed * Time.deltaTime);

            if (Mathf.Approximately(transitionSource.volume, targetVolume))
            {
                isFading = false;

                // Swap sources
                if (targetVolume >= 0.5f)
                {
                    musicSource.clip = transitionSource.clip;
                    musicSource.volume = 1f;
                    transitionSource.volume = 0f;
                    transitionSource.Stop();
                }
                else
                {
                    // Keep current music
                }
            }
        }
    }

    public void PlayMenuMusic()
    {
        PlayMusic(menuMusic);
    }

    public void PlayGameplayMusic()
    {
        PlayMusic(gameplayMusic);
    }

    public void PlayBossMusic()
    {
        PlayMusic(bossMusic);
    }

    public void PlayVictoryMusic()
    {
        PlayMusic(victoryMusic);
    }

    public void PlayMusic(AudioClip clip, bool crossfade = true)
    {
        if (clip == null)
        {
            Debug.LogWarning("Music clip is null!");
            return;
        }

        if (musicSource.clip == clip)
        {
            return;  // Already playing
        }

        if (crossfade)
        {
            CrossfadeTo(clip);
        }
        else
        {
            musicSource.clip = clip;
            musicSource.Play();
        }

        Debug.Log("Playing music: " + clip.name);
    }

    public void CrossfadeTo(AudioClip clip)
    {
        if (clip == null) return;

        transitionSource.clip = clip;
        transitionSource.volume = 0f;
        transitionSource.Play();

        targetVolume = 1f;
        isFading = true;
    }

    public void StopMusic()
    {
        musicSource.Stop();
        transitionSource.Stop();
        isFading = false;
    }

    public void PauseMusic()
    {
        musicSource.Pause();
    }

    public void ResumeMusic()
    {
        musicSource.UnPause();
    }

    public void SetVolume(float volume)
    {
        musicSource.volume = Mathf.Clamp01(volume);
    }
}

