using UnityEngine;

public class MusicError : MonoBehaviour
{
    public AudioClip music;

    void Start()
    {
        // Forgot to assign AudioSource!
        AudioSource.PlayClipAtPoint(music, Vector3.zero);  // This plays once, not looping
    }
}

phase2.explanation:
`PlayClipAtPoint` plays a clip once, not looping. Use an AudioSource for looping music.

**The fix:**
```csharp
void Start()
{
    AudioSource source = GetComponent<AudioSource>();
    if (source == null)
    {
        source = gameObject.AddComponent<AudioSource>();
    }

    source.clip = music;
    source.loop = true;
    source.Play();
}
```

**Sharp-chan says:**
"For looping music, use an AudioSource with `loop = true`."
